CREATE OR REPLACE FUNCTION stock.entree_reception(p_data jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_depot_id int := (p_data->>'depot_id')::int;
  v_ref text := coalesce(p_data->>'reception_ref', 'RECEPTION');
  v_lignes jsonb := p_data->'lignes';
  v_ligne jsonb;
  v_article_id int;
  v_quantite numeric;
  v_prix numeric;
  v_nb_articles int := 0;
  v_total_qty numeric := 0;
  v_total_valeur numeric := 0;
BEGIN
  IF NOT EXISTS (SELECT 1 FROM stock.depot WHERE id = v_depot_id AND actif) THEN
    RETURN jsonb_build_object('ok', false, 'error', pgv.t('stock.err_depot_inactive'));
  END IF;

  IF v_lignes IS NULL OR jsonb_array_length(v_lignes) = 0 THEN
    RETURN jsonb_build_object('ok', false, 'error', pgv.t('stock.err_no_lignes'));
  END IF;

  FOR i IN 0 .. jsonb_array_length(v_lignes) - 1 LOOP
    v_ligne := v_lignes->i;
    v_article_id := (v_ligne->>'article_id')::int;
    v_quantite := (v_ligne->>'quantite')::numeric;
    v_prix := (v_ligne->>'prix_unitaire')::numeric;

    IF NOT EXISTS (SELECT 1 FROM stock.article WHERE id = v_article_id AND active) THEN
      CONTINUE;
    END IF;

    IF v_quantite IS NULL OR v_quantite <= 0 THEN
      CONTINUE;
    END IF;

    INSERT INTO stock.mouvement (article_id, depot_id, type, quantite, prix_unitaire, reference)
    VALUES (v_article_id, v_depot_id, 'entree', v_quantite, v_prix, v_ref);

    PERFORM stock._recalc_pmp(v_article_id);

    IF v_prix IS NOT NULL THEN
      UPDATE stock.article SET prix_achat = v_prix WHERE id = v_article_id;
    END IF;

    v_nb_articles := v_nb_articles + 1;
    v_total_qty := v_total_qty + v_quantite;
    v_total_valeur := v_total_valeur + coalesce(v_quantite * v_prix, 0);
  END LOOP;

  RETURN jsonb_build_object(
    'ok', true,
    'nb_articles', v_nb_articles,
    'total_quantite', v_total_qty,
    'total_valeur', round(v_total_valeur, 2),
    'depot_id', v_depot_id,
    'reference', v_ref
  );
END;
$function$;
COMMENT ON FUNCTION stock.entree_reception(jsonb) IS 'Create stock entry movements from a purchase reception (i18n)';

CREATE OR REPLACE FUNCTION stock.get_alertes()
 RETURNS text
 LANGUAGE plpgsql
 STABLE
AS $function$
DECLARE
  v_body text;
  v_rows text[];
  r record;
  v_qty numeric;
BEGIN
  v_rows := ARRAY[]::text[];
  FOR r IN
    SELECT a.id, a.reference, a.designation, a.unite, a.seuil_mini, a.fournisseur_id,
           c.name AS fournisseur
    FROM stock.article a
    LEFT JOIN crm.client c ON c.id = a.fournisseur_id
    WHERE a.active AND a.seuil_mini > 0
    ORDER BY a.designation
  LOOP
    v_qty := stock._stock_actuel(r.id);
    IF v_qty < r.seuil_mini THEN
      v_rows := v_rows || ARRAY[
        format('<a href="%s">%s</a>', pgv.call_ref('get_article', jsonb_build_object('p_id', r.id)), pgv.esc(r.reference)),
        pgv.esc(r.designation),
        v_qty::text || ' ' || r.unite,
        r.seuil_mini::text || ' ' || r.unite,
        pgv.badge(pgv.t('stock.col_alerte'), 'danger'),
        CASE WHEN r.fournisseur IS NOT NULL
          THEN format('<a href="/crm/client?p_id=%s">%s</a>', r.fournisseur_id, pgv.esc(r.fournisseur))
          ELSE '—'
        END
      ];
    END IF;
  END LOOP;

  IF array_length(v_rows, 1) IS NULL THEN
    v_body := pgv.empty(pgv.t('stock.empty_no_alerte'), pgv.t('stock.empty_all_above'));
  ELSE
    v_body := pgv.md_table(
      ARRAY[pgv.t('stock.col_ref'), pgv.t('stock.col_designation'), pgv.t('stock.col_stock'), pgv.t('stock.col_seuil'), pgv.t('stock.col_statut'), pgv.t('stock.col_fournisseur')],
      v_rows
    );
  END IF;

  RETURN v_body;
END;
$function$;
COMMENT ON FUNCTION stock.get_alertes() IS 'Articles sous seuil minimum d''alerte, lien fournisseur CRM (i18n)';

CREATE OR REPLACE FUNCTION stock.get_article(p_id integer)
 RETURNS text
 LANGUAGE plpgsql
 STABLE
AS $function$
DECLARE
  v_art stock.article;
  v_body text;
  v_rows text[];
  v_fournisseur text;
  v_fournisseur_link text;
  v_stock_total numeric;
  v_catalog_link text;
  r record;
BEGIN
  SELECT * INTO v_art FROM stock.article WHERE id = p_id;
  IF NOT FOUND THEN RETURN pgv.empty(pgv.t('stock.empty_article_not_found'), ''); END IF;

  SELECT name INTO v_fournisseur FROM crm.client WHERE id = v_art.fournisseur_id;
  v_stock_total := stock._stock_actuel(p_id);

  -- Fournisseur avec lien CRM
  IF v_fournisseur IS NOT NULL THEN
    v_fournisseur_link := format('<a href="/crm/client?p_id=%s">%s</a>', v_art.fournisseur_id, pgv.esc(v_fournisseur));
  ELSE
    v_fournisseur_link := '—';
  END IF;

  -- Lien catalog (cross-module, guard pg_proc)
  v_catalog_link := '—';
  IF v_art.catalog_article_id IS NOT NULL
    AND EXISTS (SELECT 1 FROM pg_namespace WHERE nspname = 'catalog')
    AND EXISTS (SELECT 1 FROM pg_proc p JOIN pg_namespace n ON n.oid = p.pronamespace WHERE n.nspname = 'catalog' AND p.proname = 'get_article')
  THEN
    v_catalog_link := format('<a href="/catalog/article?p_id=%s">%s</a>', v_art.catalog_article_id, pgv.t('stock.cross_catalog_voir'));
  ELSIF v_art.catalog_article_id IS NOT NULL THEN
    v_catalog_link := format('#%s (%s)', v_art.catalog_article_id, pgv.t('stock.cross_catalog_unavailable'));
  END IF;

  -- Header stats
  v_body := pgv.grid(VARIADIC ARRAY[
    pgv.stat(pgv.t('stock.stat_stock_total'), v_stock_total::text || ' ' || v_art.unite),
    pgv.stat(pgv.t('stock.stat_pmp'), CASE WHEN v_art.pmp > 0 THEN to_char(v_art.pmp, 'FM999G990D00') || ' EUR' ELSE '—' END),
    pgv.stat(pgv.t('stock.stat_seuil_mini'), CASE WHEN v_art.seuil_mini > 0 THEN v_art.seuil_mini::text || ' ' || v_art.unite ELSE '—' END),
    pgv.stat(pgv.t('stock.stat_fournisseur'), v_fournisseur_link)
  ]);

  -- Info
  v_body := v_body || format('<p><strong>%s</strong> %s | <strong>%s</strong> %s | <strong>%s</strong> %s</p>',
    pgv.t('stock.label_ref'), pgv.esc(v_art.reference),
    pgv.t('stock.label_categorie'), pgv.badge(v_art.categorie, NULL),
    pgv.t('stock.label_actif'), CASE WHEN v_art.active THEN pgv.t('stock.yes') ELSE pgv.t('stock.no') END
  );

  -- Catalog link
  IF v_catalog_link <> '—' THEN
    v_body := v_body || format('<p><strong>%s</strong> %s</p>', pgv.t('stock.label_catalog'), v_catalog_link);
  END IF;

  -- Stock par dépôt
  v_rows := ARRAY[]::text[];
  FOR r IN
    SELECT d.id, d.nom, stock._stock_actuel(p_id, d.id) AS qty
    FROM stock.depot d
    WHERE d.actif
      AND EXISTS (SELECT 1 FROM stock.mouvement m WHERE m.article_id = p_id AND m.depot_id = d.id)
    ORDER BY d.nom
  LOOP
    v_rows := v_rows || ARRAY[
      pgv.esc(r.nom),
      r.qty::text || ' ' || v_art.unite
    ];
  END LOOP;

  IF array_length(v_rows, 1) IS NOT NULL THEN
    v_body := v_body || '<h3>' || pgv.t('stock.title_stock_depot') || '</h3>' || pgv.md_table(
      ARRAY[pgv.t('stock.col_depot'), pgv.t('stock.col_quantite')],
      v_rows
    );
  END IF;

  -- Derniers mouvements
  v_rows := ARRAY[]::text[];
  FOR r IN
    SELECT m.created_at, d.nom AS depot_nom, m.type, m.quantite, m.prix_unitaire, m.reference
    FROM stock.mouvement m
    JOIN stock.depot d ON d.id = m.depot_id
    WHERE m.article_id = p_id
    ORDER BY m.created_at DESC
    LIMIT 20
  LOOP
    v_rows := v_rows || ARRAY[
      to_char(r.created_at, 'DD/MM HH24:MI'),
      pgv.esc(r.depot_nom),
      pgv.badge(r.type, CASE r.type
        WHEN 'entree' THEN 'success'
        WHEN 'sortie' THEN 'danger'
        WHEN 'transfert' THEN 'info'
        WHEN 'inventaire' THEN 'warning'
      END),
      r.quantite::text,
      CASE WHEN r.prix_unitaire IS NOT NULL THEN to_char(r.prix_unitaire, 'FM999G990D00') ELSE '—' END,
      coalesce(r.reference, '')
    ];
  END LOOP;

  IF array_length(v_rows, 1) IS NOT NULL THEN
    v_body := v_body || '<h3>' || pgv.t('stock.title_mvt_recents') || '</h3>' || pgv.md_table(
      ARRAY[pgv.t('stock.col_date'), pgv.t('stock.col_depot'), pgv.t('stock.col_type'), pgv.t('stock.col_qty'), pgv.t('stock.col_pu'), pgv.t('stock.col_ref')],
      v_rows, 10
    );
  END IF;

  -- Actions
  v_body := v_body || format('<p><a href="%s" role="button">%s</a> ',
    pgv.call_ref('get_article_form', jsonb_build_object('p_id', p_id)), pgv.t('stock.btn_modifier'));
  v_body := v_body || pgv.action('post_article_delete', pgv.t('stock.btn_desactiver'),
    jsonb_build_object('id', p_id), pgv.t('stock.confirm_desactiver')) || '</p>';

  RETURN v_body;
END;
$function$;
COMMENT ON FUNCTION stock.get_article(integer) IS 'Fiche article: infos, stock par dépôt, historique mouvements, lien fournisseur CRM, lien catalog (i18n)';

CREATE OR REPLACE FUNCTION stock.get_article_form(p_id integer DEFAULT NULL::integer)
 RETURNS text
 LANGUAGE plpgsql
 STABLE
AS $function$
DECLARE
  v_art stock.article;
  v_body text;
  v_cat_opts jsonb;
  v_unit_opts jsonb;
  v_fournisseur_opts jsonb;
  v_catalog_search text;
  v_catalog_display text;
BEGIN
  IF p_id IS NOT NULL THEN
    SELECT * INTO v_art FROM stock.article WHERE id = p_id;
    IF NOT FOUND THEN RETURN pgv.empty(pgv.t('stock.empty_article_not_found'), ''); END IF;
  END IF;

  -- Options catégorie
  v_cat_opts := jsonb_build_array(
    jsonb_build_object('value', 'bois', 'label', pgv.t('stock.cat_bois')),
    jsonb_build_object('value', 'quincaillerie', 'label', pgv.t('stock.cat_quincaillerie')),
    jsonb_build_object('value', 'panneau', 'label', pgv.t('stock.cat_panneau')),
    jsonb_build_object('value', 'isolant', 'label', pgv.t('stock.cat_isolant')),
    jsonb_build_object('value', 'finition', 'label', pgv.t('stock.cat_finition')),
    jsonb_build_object('value', 'autre', 'label', pgv.t('stock.cat_autre'))
  );

  -- Options unité
  v_unit_opts := jsonb_build_array(
    jsonb_build_object('value', 'u', 'label', pgv.t('stock.unit_u')),
    jsonb_build_object('value', 'm', 'label', pgv.t('stock.unit_m')),
    jsonb_build_object('value', 'm2', 'label', pgv.t('stock.unit_m2')),
    jsonb_build_object('value', 'm3', 'label', pgv.t('stock.unit_m3')),
    jsonb_build_object('value', 'kg', 'label', pgv.t('stock.unit_kg')),
    jsonb_build_object('value', 'l', 'label', pgv.t('stock.unit_l'))
  );

  -- Options fournisseur (CRM companies)
  SELECT coalesce(jsonb_agg(jsonb_build_object('value', c.id::text, 'label', c.name) ORDER BY c.name), '[]'::jsonb)
  INTO v_fournisseur_opts
  FROM crm.client c WHERE c.type = 'company' AND c.active;

  -- Catalog article search (cross-module guard)
  v_catalog_search := '';
  IF EXISTS (SELECT 1 FROM pg_namespace WHERE nspname = 'catalog') THEN
    v_catalog_display := NULL;
    IF v_art.catalog_article_id IS NOT NULL THEN
      SELECT ca.designation INTO v_catalog_display
      FROM catalog.article ca WHERE ca.id = v_art.catalog_article_id;
    END IF;
    v_catalog_search := pgv.select_search(
      'catalog_article_id', pgv.t('stock.field_article_catalog'),
      'catalog.article_options',
      pgv.t('stock.ph_search_catalog'),
      v_art.catalog_article_id::text,
      v_catalog_display
    );
  END IF;

  v_body := '<input type="hidden" name="id" value="' || coalesce(p_id::text, '') || '">'
    || pgv.input('reference', 'text', pgv.t('stock.field_reference'), coalesce(v_art.reference, ''), true)
    || pgv.input('designation', 'text', pgv.t('stock.field_designation'), coalesce(v_art.designation, ''), true)
    || pgv.sel('categorie', pgv.t('stock.field_categorie'), v_cat_opts, v_art.categorie)
    || pgv.sel('unite', pgv.t('stock.field_unite'), v_unit_opts, coalesce(v_art.unite, 'u'))
    || pgv.input('prix_achat', 'number', pgv.t('stock.field_prix_achat'), coalesce(v_art.prix_achat::text, ''))
    || pgv.input('seuil_mini', 'number', pgv.t('stock.field_seuil_mini'), coalesce(v_art.seuil_mini::text, '0'))
    || pgv.sel('fournisseur_id', pgv.t('stock.field_fournisseur'), v_fournisseur_opts, v_art.fournisseur_id::text)
    || v_catalog_search
    || pgv.textarea('notes', pgv.t('stock.field_notes'), v_art.notes);

  RETURN pgv.form('post_article_save', v_body,
    CASE WHEN p_id IS NOT NULL THEN pgv.t('stock.btn_modifier') ELSE pgv.t('stock.btn_creer') END);
END;
$function$;
COMMENT ON FUNCTION stock.get_article_form(integer) IS 'Formulaire création/édition article avec select fournisseur CRM et lien catalog (i18n, primitives)';

CREATE OR REPLACE FUNCTION stock.get_articles()
 RETURNS text
 LANGUAGE plpgsql
 STABLE
AS $function$
DECLARE
  v_body text;
  v_rows text[];
  r record;
BEGIN
  v_rows := ARRAY[]::text[];
  FOR r IN
    SELECT a.id, a.reference, a.designation, a.categorie, a.unite,
           a.prix_achat, a.pmp, a.seuil_mini, a.active, a.fournisseur_id,
           stock._stock_actuel(a.id) AS qty,
           c.name AS fournisseur
    FROM stock.article a
    LEFT JOIN crm.client c ON c.id = a.fournisseur_id
    ORDER BY a.designation
  LOOP
    v_rows := v_rows || ARRAY[
      format('<a href="%s">%s</a>', pgv.call_ref('get_article', jsonb_build_object('p_id', r.id)), pgv.esc(r.reference)),
      pgv.esc(r.designation),
      pgv.badge(r.categorie, CASE r.categorie
        WHEN 'bois' THEN 'success'
        WHEN 'quincaillerie' THEN 'info'
        WHEN 'panneau' THEN 'warning'
        ELSE NULL
      END),
      r.qty::text || ' ' || r.unite,
      CASE WHEN r.pmp > 0 THEN to_char(r.pmp, 'FM999G990D00') ELSE '—' END,
      CASE WHEN r.seuil_mini > 0 AND r.qty < r.seuil_mini
        THEN pgv.badge(pgv.t('stock.col_alerte'), 'danger')
        ELSE '—'
      END,
      CASE WHEN r.fournisseur IS NOT NULL
        THEN format('<a href="/crm/client?p_id=%s">%s</a>', r.fournisseur_id, pgv.esc(r.fournisseur))
        ELSE '—'
      END,
      CASE WHEN r.active THEN pgv.t('stock.yes') ELSE pgv.t('stock.no') END
    ];
  END LOOP;

  IF array_length(v_rows, 1) IS NULL THEN
    v_body := pgv.empty(pgv.t('stock.empty_no_article'), pgv.t('stock.empty_first_article'));
  ELSE
    v_body := pgv.md_table(
      ARRAY[pgv.t('stock.col_ref'), pgv.t('stock.col_designation'), pgv.t('stock.col_categorie'), pgv.t('stock.col_stock'), pgv.t('stock.col_pmp'), pgv.t('stock.col_alerte'), pgv.t('stock.col_fournisseur'), pgv.t('stock.col_actif')],
      v_rows,
      20
    );
  END IF;

  v_body := v_body || format('<p><a href="%s" role="button">%s</a></p>',
    pgv.call_ref('get_article_form'), pgv.t('stock.btn_nouvel_article'));

  RETURN v_body;
END;
$function$;
COMMENT ON FUNCTION stock.get_articles() IS 'Liste des articles avec stock actuel, PMP, alertes, lien fournisseur CRM (i18n)';

CREATE OR REPLACE FUNCTION stock.get_depot(p_id integer)
 RETURNS text
 LANGUAGE plpgsql
 STABLE
AS $function$
DECLARE
  v_dep stock.depot;
  v_body text;
  v_rows text[];
  r record;
BEGIN
  SELECT * INTO v_dep FROM stock.depot WHERE id = p_id;
  IF NOT FOUND THEN RETURN pgv.empty(pgv.t('stock.empty_depot_not_found'), ''); END IF;

  v_body := format('<p><strong>%s</strong> %s | <strong>%s</strong> %s | <strong>%s</strong> %s</p>',
    pgv.t('stock.label_type'), pgv.badge(v_dep.type, NULL),
    pgv.t('stock.label_adresse'), coalesce(pgv.esc(v_dep.adresse), '—'),
    pgv.t('stock.label_actif'), CASE WHEN v_dep.actif THEN pgv.t('stock.yes') ELSE pgv.t('stock.no') END
  );

  -- Contenu du dépôt
  v_rows := ARRAY[]::text[];
  FOR r IN
    SELECT a.id, a.reference, a.designation, a.unite,
           stock._stock_actuel(a.id, p_id) AS qty
    FROM stock.article a
    WHERE a.active
      AND EXISTS (SELECT 1 FROM stock.mouvement m WHERE m.article_id = a.id AND m.depot_id = p_id)
    ORDER BY a.designation
  LOOP
    IF r.qty <> 0 THEN
      v_rows := v_rows || ARRAY[
        format('<a href="%s">%s</a>', pgv.call_ref('get_article', jsonb_build_object('p_id', r.id)), pgv.esc(r.reference)),
        pgv.esc(r.designation),
        r.qty::text || ' ' || r.unite
      ];
    END IF;
  END LOOP;

  IF array_length(v_rows, 1) IS NOT NULL THEN
    v_body := v_body || '<h3>' || pgv.t('stock.title_contenu') || '</h3>' || pgv.md_table(
      ARRAY[pgv.t('stock.col_ref'), pgv.t('stock.col_designation'), pgv.t('stock.col_quantite')],
      v_rows
    );
  ELSE
    v_body := v_body || pgv.empty(pgv.t('stock.empty_depot_vide'), '');
  END IF;

  -- Derniers mouvements
  v_rows := ARRAY[]::text[];
  FOR r IN
    SELECT m.created_at, a.designation, m.type, m.quantite, m.reference
    FROM stock.mouvement m
    JOIN stock.article a ON a.id = m.article_id
    WHERE m.depot_id = p_id
    ORDER BY m.created_at DESC
    LIMIT 20
  LOOP
    v_rows := v_rows || ARRAY[
      to_char(r.created_at, 'DD/MM HH24:MI'),
      pgv.esc(r.designation),
      pgv.badge(r.type, CASE r.type
        WHEN 'entree' THEN 'success'
        WHEN 'sortie' THEN 'danger'
        WHEN 'transfert' THEN 'info'
        WHEN 'inventaire' THEN 'warning'
      END),
      r.quantite::text,
      coalesce(r.reference, '')
    ];
  END LOOP;

  IF array_length(v_rows, 1) IS NOT NULL THEN
    v_body := v_body || '<h3>' || pgv.t('stock.title_mvt_recents') || '</h3>' || pgv.md_table(
      ARRAY[pgv.t('stock.col_date'), pgv.t('stock.col_article'), pgv.t('stock.col_type'), pgv.t('stock.col_qty'), pgv.t('stock.col_ref')],
      v_rows, 10
    );
  END IF;

  v_body := v_body || format('<p><a href="%s" role="button">%s</a></p>',
    pgv.call_ref('get_depot_form', jsonb_build_object('p_id', p_id)), pgv.t('stock.btn_modifier'));

  RETURN v_body;
END;
$function$;
COMMENT ON FUNCTION stock.get_depot(integer) IS 'Fiche dépôt: contenu + mouvements récents (i18n)';

CREATE OR REPLACE FUNCTION stock.get_depot_form(p_id integer DEFAULT NULL::integer)
 RETURNS text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_dep stock.depot;
  v_type_opts jsonb;
  v_body text;
BEGIN
  IF p_id IS NOT NULL THEN
    SELECT * INTO v_dep FROM stock.depot WHERE id = p_id;
    IF NOT FOUND THEN RETURN pgv.empty(pgv.t('stock.empty_depot_not_found'), ''); END IF;
  END IF;

  v_type_opts := jsonb_build_array(
    jsonb_build_object('value', '', 'label', pgv.t('stock.ph_type')),
    jsonb_build_object('value', 'atelier', 'label', pgv.t('stock.depot_atelier')),
    jsonb_build_object('value', 'chantier', 'label', pgv.t('stock.depot_chantier')),
    jsonb_build_object('value', 'vehicule', 'label', pgv.t('stock.depot_vehicule')),
    jsonb_build_object('value', 'entrepot', 'label', pgv.t('stock.depot_entrepot'))
  );

  v_body := '<input type="hidden" name="id" value="' || coalesce(p_id::text, '') || '">'
    || pgv.input('nom', 'text', pgv.t('stock.field_nom'), coalesce(pgv.esc(v_dep.nom), ''), true)
    || pgv.sel('type', pgv.t('stock.field_type'), v_type_opts, coalesce(v_dep.type, ''))
    || pgv.input('adresse', 'text', pgv.t('stock.field_adresse'), coalesce(pgv.esc(v_dep.adresse), ''));

  RETURN pgv.form('post_depot_save', v_body,
    CASE WHEN p_id IS NOT NULL THEN pgv.t('stock.btn_modifier') ELSE pgv.t('stock.btn_creer') END);
END;
$function$;
COMMENT ON FUNCTION stock.get_depot_form(integer) IS 'Formulaire création/édition dépôt (i18n + pgv primitives)';

CREATE OR REPLACE FUNCTION stock.get_depots()
 RETURNS text
 LANGUAGE plpgsql
 STABLE
AS $function$
DECLARE
  v_body text;
  v_rows text[];
  r record;
BEGIN
  v_rows := ARRAY[]::text[];
  FOR r IN
    SELECT d.id, d.nom, d.type, d.adresse, d.actif,
           (SELECT count(DISTINCT m.article_id) FROM stock.mouvement m WHERE m.depot_id = d.id)::int AS nb_articles
    FROM stock.depot d
    ORDER BY d.nom
  LOOP
    v_rows := v_rows || ARRAY[
      format('<a href="%s">%s</a>', pgv.call_ref('get_depot', jsonb_build_object('p_id', r.id)), pgv.esc(r.nom)),
      pgv.badge(r.type, CASE r.type
        WHEN 'atelier' THEN 'success'
        WHEN 'chantier' THEN 'warning'
        WHEN 'vehicule' THEN 'info'
        WHEN 'entrepot' THEN NULL
      END),
      coalesce(r.adresse, '—'),
      r.nb_articles::text,
      CASE WHEN r.actif THEN pgv.t('stock.yes') ELSE pgv.t('stock.no') END
    ];
  END LOOP;

  IF array_length(v_rows, 1) IS NULL THEN
    v_body := pgv.empty(pgv.t('stock.empty_no_depot'), pgv.t('stock.empty_first_depot'));
  ELSE
    v_body := pgv.md_table(
      ARRAY[pgv.t('stock.col_nom'), pgv.t('stock.col_type'), pgv.t('stock.col_adresse'), pgv.t('stock.col_articles'), pgv.t('stock.col_actif')],
      v_rows
    );
  END IF;

  v_body := v_body || format('<p><a href="%s" role="button">%s</a></p>',
    pgv.call_ref('get_depot_form'), pgv.t('stock.btn_nouveau_depot'));

  RETURN v_body;
END;
$function$;
COMMENT ON FUNCTION stock.get_depots() IS 'Liste des dépôts avec nombre d''articles stockés (i18n)';

CREATE OR REPLACE FUNCTION stock.get_index()
 RETURNS text
 LANGUAGE plpgsql
 STABLE
AS $function$
DECLARE
  v_nb_articles int;
  v_nb_alertes int;
  v_mvt_semaine int;
  v_mvt_semaine_prec int;
  v_valeur_totale numeric;
  v_body text;
  v_rows text[];
  v_variation text;
  r record;
BEGIN
  SELECT count(*)::int INTO v_nb_articles FROM stock.article WHERE active;

  -- Articles sous seuil
  SELECT count(*)::int INTO v_nb_alertes
  FROM stock.article a
  WHERE a.active AND a.seuil_mini > 0
    AND stock._stock_actuel(a.id) < a.seuil_mini;

  -- Tendance semaine
  SELECT count(*)::int INTO v_mvt_semaine
  FROM stock.mouvement
  WHERE created_at >= date_trunc('week', now());

  SELECT count(*)::int INTO v_mvt_semaine_prec
  FROM stock.mouvement
  WHERE created_at >= date_trunc('week', now()) - interval '7 days'
    AND created_at < date_trunc('week', now());

  IF v_mvt_semaine_prec > 0 THEN
    v_variation := CASE
      WHEN v_mvt_semaine > v_mvt_semaine_prec THEN '+' || round(((v_mvt_semaine - v_mvt_semaine_prec)::numeric / v_mvt_semaine_prec) * 100)::text || '%'
      WHEN v_mvt_semaine < v_mvt_semaine_prec THEN '-' || round(((v_mvt_semaine_prec - v_mvt_semaine)::numeric / v_mvt_semaine_prec) * 100)::text || '%'
      ELSE '='
    END;
  ELSE
    v_variation := NULL;
  END IF;

  -- Valeur totale du stock (quantité * PMP par article)
  SELECT coalesce(sum(stock._stock_actuel(a.id) * a.pmp), 0)
  INTO v_valeur_totale
  FROM stock.article a
  WHERE a.active AND a.pmp > 0;

  v_body := pgv.grid(VARIADIC ARRAY[
    pgv.stat(pgv.t('stock.stat_articles'), v_nb_articles::text),
    pgv.stat(pgv.t('stock.stat_valeur_stock'), to_char(v_valeur_totale, 'FM999G999G990D00') || ' EUR'),
    pgv.stat(pgv.t('stock.stat_alertes'), v_nb_alertes::text, CASE WHEN v_nb_alertes > 0 THEN 'danger' ELSE NULL END),
    pgv.stat(pgv.t('stock.stat_mvt_semaine'), v_mvt_semaine::text || coalesce(' (' || v_variation || ')', ''))
  ]);

  -- Alertes stock bas
  IF v_nb_alertes > 0 THEN
    v_rows := ARRAY[]::text[];
    FOR r IN
      SELECT a.id, a.reference, a.designation, a.unite, a.seuil_mini, stock._stock_actuel(a.id) AS qty
      FROM stock.article a
      WHERE a.active AND a.seuil_mini > 0
        AND stock._stock_actuel(a.id) < a.seuil_mini
      ORDER BY (stock._stock_actuel(a.id) / a.seuil_mini)
      LIMIT 10
    LOOP
      v_rows := v_rows || ARRAY[
        format('<a href="%s">%s</a>',
          pgv.call_ref('get_article', jsonb_build_object('p_id', r.id)),
          pgv.esc(r.designation)),
        pgv.esc(r.reference),
        pgv.badge(r.qty::text || ' ' || r.unite, 'danger'),
        r.seuil_mini::text || ' ' || r.unite
      ];
    END LOOP;
    v_body := v_body || '<h3>' || pgv.t('stock.title_stock_bas') || '</h3>' || pgv.md_table(
      ARRAY[pgv.t('stock.col_article'), pgv.t('stock.col_ref'), pgv.t('stock.col_stock_actuel'), pgv.t('stock.col_seuil')],
      v_rows
    );
  END IF;

  -- Top 5 articles ce mois
  v_rows := ARRAY[]::text[];
  FOR r IN
    SELECT a.id, a.designation, count(*) AS nb_mvt, sum(m.quantite) AS total_qty
    FROM stock.mouvement m
    JOIN stock.article a ON a.id = m.article_id
    WHERE m.created_at >= date_trunc('month', now())
    GROUP BY a.id, a.designation
    ORDER BY nb_mvt DESC
    LIMIT 5
  LOOP
    v_rows := v_rows || ARRAY[
      format('<a href="%s">%s</a>',
        pgv.call_ref('get_article', jsonb_build_object('p_id', r.id)),
        pgv.esc(r.designation)),
      r.nb_mvt::text,
      r.total_qty::text
    ];
  END LOOP;

  IF array_length(v_rows, 1) IS NOT NULL THEN
    v_body := v_body || '<h3>' || pgv.t('stock.title_top_articles') || '</h3>' || pgv.md_table(
      ARRAY[pgv.t('stock.col_article'), pgv.t('stock.col_mouvements'), pgv.t('stock.col_qty_totale')],
      v_rows
    );
  END IF;

  -- Derniers mouvements
  v_rows := ARRAY[]::text[];
  FOR r IN
    SELECT m.created_at, a.designation, d.nom AS depot_nom, m.type, m.quantite, m.reference
    FROM stock.mouvement m
    JOIN stock.article a ON a.id = m.article_id
    JOIN stock.depot d ON d.id = m.depot_id
    ORDER BY m.created_at DESC
    LIMIT 10
  LOOP
    v_rows := v_rows || ARRAY[
      to_char(r.created_at, 'DD/MM HH24:MI'),
      pgv.esc(r.designation),
      pgv.esc(r.depot_nom),
      pgv.badge(r.type, CASE r.type
        WHEN 'entree' THEN 'success'
        WHEN 'sortie' THEN 'danger'
        WHEN 'transfert' THEN 'info'
        WHEN 'inventaire' THEN 'warning'
      END),
      r.quantite::text,
      coalesce(r.reference, '')
    ];
  END LOOP;

  IF array_length(v_rows, 1) IS NULL THEN
    v_body := v_body || pgv.empty(pgv.t('stock.empty_no_mouvement'), pgv.t('stock.empty_first_mouvement'));
  ELSE
    v_body := v_body || '<h3>' || pgv.t('stock.title_derniers_mvt') || '</h3>' || pgv.md_table(
      ARRAY[pgv.t('stock.col_date'), pgv.t('stock.col_article'), pgv.t('stock.col_depot'), pgv.t('stock.col_type'), pgv.t('stock.col_qty'), pgv.t('stock.col_ref')],
      v_rows
    );
  END IF;

  v_body := v_body || format('<p><a href="%s" role="button">%s</a></p>',
    pgv.call_ref('get_mouvement_form'), pgv.t('stock.btn_nouveau_mvt'));

  RETURN v_body;
END;
$function$;
COMMENT ON FUNCTION stock.get_index() IS 'Dashboard stock: stats tendance, alertes stock bas, top articles, derniers mouvements (i18n)';

CREATE OR REPLACE FUNCTION stock.get_inventaire(p_depot_id integer DEFAULT NULL::integer)
 RETURNS text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_body text;
  v_depot_nom text;
  v_rows text[];
  r record;
  v_qty numeric;
  v_form_body text;
BEGIN
  -- Si pas de dépôt sélectionné, afficher le choix
  IF p_depot_id IS NULL THEN
    v_rows := ARRAY[]::text[];
    FOR r IN
      SELECT d.id, d.nom, d.type FROM stock.depot d WHERE d.actif ORDER BY d.nom
    LOOP
      v_rows := v_rows || ARRAY[
        format('<a href="%s">%s</a>',
          pgv.call_ref('get_inventaire', jsonb_build_object('p_depot_id', r.id)),
          pgv.esc(r.nom)),
        pgv.badge(r.type, CASE r.type
          WHEN 'entrepot' THEN 'info'
          WHEN 'atelier' THEN 'success'
          WHEN 'chantier' THEN 'warning'
          WHEN 'vehicule' THEN 'primary'
        END)
      ];
    END LOOP;

    IF array_length(v_rows, 1) IS NULL THEN
      RETURN pgv.empty(pgv.t('stock.empty_no_depot'), pgv.t('stock.empty_depot_create_first'));
    END IF;

    RETURN '<p>' || pgv.t('stock.title_select_depot') || '</p>' || pgv.md_table(
      ARRAY[pgv.t('stock.col_depot'), pgv.t('stock.col_type')],
      v_rows
    );
  END IF;

  SELECT nom INTO v_depot_nom FROM stock.depot WHERE id = p_depot_id AND actif;
  IF v_depot_nom IS NULL THEN
    RETURN pgv.empty(pgv.t('stock.empty_depot_not_found'), pgv.t('stock.empty_depot_inactive'));
  END IF;

  v_body := format('<h3>%s : %s</h3>', pgv.t('stock.nav_inventaire'), pgv.esc(v_depot_nom));

  -- Liste des articles avec stock théorique
  v_rows := ARRAY[]::text[];
  FOR r IN
    SELECT a.id, a.reference, a.designation, a.unite
    FROM stock.article a
    WHERE a.active
    ORDER BY a.designation
  LOOP
    v_qty := stock._stock_actuel(r.id, p_depot_id);
    v_rows := v_rows || ARRAY[
      pgv.esc(r.reference),
      pgv.esc(r.designation),
      r.unite,
      v_qty::text,
      format('<input type="number" name="qty_%s" value="%s" step="0.01" class="pgv-input-sm">', r.id, v_qty)
    ];
  END LOOP;

  IF array_length(v_rows, 1) IS NULL THEN
    v_form_body := format('<input type="hidden" name="p_depot_id" value="%s">', p_depot_id)
      || pgv.empty(pgv.t('stock.empty_no_article'), pgv.t('stock.empty_no_article_actif'));
    v_body := v_body || pgv.form('post_inventaire_valider', v_form_body, pgv.t('stock.btn_valider_inventaire'));
    RETURN v_body;
  END IF;

  v_form_body := format('<input type="hidden" name="p_depot_id" value="%s">', p_depot_id)
    || pgv.md_table(
      ARRAY[pgv.t('stock.col_ref'), pgv.t('stock.col_designation'), pgv.t('stock.col_unite'), pgv.t('stock.col_theorique'), pgv.t('stock.col_reel')],
      v_rows
    );

  v_body := v_body || pgv.form('post_inventaire_valider', v_form_body, pgv.t('stock.btn_valider_inventaire'));

  RETURN v_body;
END;
$function$;
COMMENT ON FUNCTION stock.get_inventaire(integer) IS 'Formulaire d inventaire physique pour un dépôt — saisie quantités réelles (i18n + pgv primitives)';

CREATE OR REPLACE FUNCTION stock.get_mouvement_form(p_type text DEFAULT 'entree'::text)
 RETURNS text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_depot_opts jsonb;
  v_type_opts jsonb;
  v_body text;
  v_article_search text;
BEGIN
  -- Article via select_search
  v_article_search := pgv.select_search(
    'article_id', pgv.t('stock.col_article'),
    'article_options',
    pgv.t('stock.ph_search_article')
  );

  -- Dépôts actifs
  SELECT coalesce(
    jsonb_build_array(jsonb_build_object('value', '', 'label', pgv.t('stock.ph_depot')))
    || jsonb_agg(jsonb_build_object('value', d.id::text, 'label', d.nom) ORDER BY d.nom),
    jsonb_build_array(jsonb_build_object('value', '', 'label', pgv.t('stock.ph_depot')))
  ) INTO v_depot_opts
  FROM stock.depot d WHERE d.actif;

  -- Type
  v_type_opts := jsonb_build_array(
    jsonb_build_object('value', 'entree', 'label', pgv.t('stock.type_entree')),
    jsonb_build_object('value', 'sortie', 'label', pgv.t('stock.type_sortie')),
    jsonb_build_object('value', 'transfert', 'label', pgv.t('stock.type_transfert')),
    jsonb_build_object('value', 'inventaire', 'label', pgv.t('stock.type_inventaire'))
  );

  v_body := pgv.sel('type', pgv.t('stock.field_type'), v_type_opts, p_type)
    || v_article_search
    || pgv.sel('depot_id', pgv.t('stock.col_depot'), v_depot_opts, '')
    || pgv.input('quantite', 'number', pgv.t('stock.field_quantite'), '', true)
    || pgv.input('prix_unitaire', 'number', pgv.t('stock.field_prix_unitaire'), '')
    || pgv.sel('depot_destination_id', pgv.t('stock.field_depot_dest'), v_depot_opts, '')
    || pgv.input('reference', 'text', pgv.t('stock.field_ref_doc'), '')
    || pgv.textarea('notes', pgv.t('stock.field_notes'), '');

  RETURN pgv.form('post_mouvement_save', v_body, pgv.t('stock.btn_enregistrer'));
END;
$function$;
COMMENT ON FUNCTION stock.get_mouvement_form(text) IS 'Formulaire de saisie mouvement avec select_search article (i18n + pgv primitives)';

CREATE OR REPLACE FUNCTION stock.get_mouvements()
 RETURNS text
 LANGUAGE plpgsql
 STABLE
AS $function$
DECLARE
  v_body text;
  v_rows text[];
  r record;
BEGIN
  v_rows := ARRAY[]::text[];
  FOR r IN
    SELECT m.id, m.created_at, a.reference, a.designation, d.nom AS depot_nom,
           m.type, m.quantite, m.prix_unitaire, m.reference AS ref_doc,
           dd.nom AS dest_nom
    FROM stock.mouvement m
    JOIN stock.article a ON a.id = m.article_id
    JOIN stock.depot d ON d.id = m.depot_id
    LEFT JOIN stock.depot dd ON dd.id = m.depot_destination_id
    ORDER BY m.created_at DESC
  LOOP
    v_rows := v_rows || ARRAY[
      to_char(r.created_at, 'DD/MM/YY HH24:MI'),
      format('<a href="%s">%s</a>', pgv.call_ref('get_article', jsonb_build_object('p_id', r.id)), pgv.esc(r.reference)),
      pgv.esc(r.designation),
      pgv.esc(r.depot_nom) || CASE WHEN r.dest_nom IS NOT NULL THEN ' -> ' || pgv.esc(r.dest_nom) ELSE '' END,
      pgv.badge(r.type, CASE r.type
        WHEN 'entree' THEN 'success'
        WHEN 'sortie' THEN 'danger'
        WHEN 'transfert' THEN 'info'
        WHEN 'inventaire' THEN 'warning'
      END),
      r.quantite::text,
      coalesce(r.ref_doc, '')
    ];
  END LOOP;

  IF array_length(v_rows, 1) IS NULL THEN
    v_body := pgv.empty(pgv.t('stock.empty_no_mouvement'), pgv.t('stock.empty_first_mouvement_short'));
  ELSE
    v_body := pgv.md_table(
      ARRAY[pgv.t('stock.col_date'), pgv.t('stock.col_ref'), pgv.t('stock.col_article'), pgv.t('stock.col_depot'), pgv.t('stock.col_type'), pgv.t('stock.col_qty'), pgv.t('stock.col_ref_doc')],
      v_rows, 20
    );
  END IF;

  v_body := v_body || format('<p><a href="%s" role="button">%s</a></p>',
    pgv.call_ref('get_mouvement_form'), pgv.t('stock.btn_nouveau_mvt'));

  RETURN v_body;
END;
$function$;
COMMENT ON FUNCTION stock.get_mouvements() IS 'Historique des mouvements de stock (i18n)';

CREATE OR REPLACE FUNCTION stock.get_valorisation()
 RETURNS text
 LANGUAGE plpgsql
 STABLE
AS $function$
DECLARE
  v_body text;
  v_valeur_totale numeric;
  v_nb_articles int;
  v_nb_alertes int;
  v_rows text[];
  r record;
BEGIN
  -- Stats globales
  SELECT count(*)::int INTO v_nb_articles FROM stock.article WHERE active;

  SELECT coalesce(sum(stock._stock_actuel(a.id) * a.pmp), 0)
  INTO v_valeur_totale
  FROM stock.article a WHERE a.active AND a.pmp > 0;

  SELECT count(*)::int INTO v_nb_alertes
  FROM stock.article a
  WHERE a.active AND a.seuil_mini > 0
    AND stock._stock_actuel(a.id) < a.seuil_mini;

  v_body := pgv.grid(VARIADIC ARRAY[
    pgv.stat(pgv.t('stock.stat_valeur_totale'), to_char(v_valeur_totale, 'FM999G999G990D00') || ' EUR'),
    pgv.stat(pgv.t('stock.stat_articles_stock'), v_nb_articles::text),
    pgv.stat(pgv.t('stock.stat_en_alerte'), v_nb_alertes::text, CASE WHEN v_nb_alertes > 0 THEN 'danger' ELSE NULL END)
  ]);

  -- Valorisation par dépôt
  v_rows := ARRAY[]::text[];
  FOR r IN
    SELECT d.nom AS depot_nom, d.type AS depot_type,
           count(DISTINCT m.article_id)::int AS nb_articles,
           coalesce(sum(m.quantite * a.pmp), 0) AS valeur
    FROM stock.depot d
    LEFT JOIN stock.mouvement m ON m.depot_id = d.id
    LEFT JOIN stock.article a ON a.id = m.article_id AND a.active
    WHERE d.actif
    GROUP BY d.id, d.nom, d.type
    ORDER BY valeur DESC
  LOOP
    v_rows := v_rows || ARRAY[
      pgv.esc(r.depot_nom),
      pgv.badge(r.depot_type, CASE r.depot_type
        WHEN 'entrepot' THEN 'info'
        WHEN 'atelier' THEN 'success'
        WHEN 'chantier' THEN 'warning'
        WHEN 'vehicule' THEN 'primary'
      END),
      r.nb_articles::text,
      to_char(r.valeur, 'FM999G999G990D00') || ' EUR'
    ];
  END LOOP;

  IF array_length(v_rows, 1) IS NOT NULL THEN
    v_body := v_body || '<h3>' || pgv.t('stock.title_par_depot') || '</h3>' || pgv.md_table(
      ARRAY[pgv.t('stock.col_depot'), pgv.t('stock.col_type'), pgv.t('stock.col_articles'), pgv.t('stock.col_valeur')],
      v_rows
    );
  END IF;

  -- Valorisation par catégorie
  v_rows := ARRAY[]::text[];
  FOR r IN
    SELECT a.categorie,
           count(*)::int AS nb_articles,
           coalesce(sum(stock._stock_actuel(a.id) * a.pmp), 0) AS valeur
    FROM stock.article a
    WHERE a.active AND a.pmp > 0
    GROUP BY a.categorie
    ORDER BY valeur DESC
  LOOP
    v_rows := v_rows || ARRAY[
      pgv.badge(r.categorie, CASE r.categorie
        WHEN 'bois' THEN 'success'
        WHEN 'quincaillerie' THEN 'info'
        WHEN 'panneau' THEN 'warning'
        WHEN 'isolant' THEN 'primary'
        WHEN 'finition' THEN 'default'
        ELSE NULL
      END),
      r.nb_articles::text,
      to_char(r.valeur, 'FM999G999G990D00') || ' EUR'
    ];
  END LOOP;

  IF array_length(v_rows, 1) IS NOT NULL THEN
    v_body := v_body || '<h3>' || pgv.t('stock.title_par_categorie') || '</h3>' || pgv.md_table(
      ARRAY[pgv.t('stock.col_categorie'), pgv.t('stock.col_articles'), pgv.t('stock.col_valeur')],
      v_rows
    );
  END IF;

  RETURN v_body;
END;
$function$;
COMMENT ON FUNCTION stock.get_valorisation() IS 'Valorisation du stock par dépôt et catégorie, avec totaux (i18n)';

CREATE OR REPLACE FUNCTION stock.i18n_seed()
 RETURNS void
 LANGUAGE plpgsql
AS $function$
BEGIN
  INSERT INTO pgv.i18n (lang, key, value) VALUES
    -- Brand / Navigation
    ('fr', 'stock.brand', 'Stock'),
