CREATE OR REPLACE FUNCTION stock.post_article_delete(p_data jsonb)
 RETURNS text
 LANGUAGE plpgsql
AS $function$
BEGIN
  UPDATE stock.article SET active = false WHERE id = (p_data->>'id')::int;

  RETURN pgv.toast(pgv.t('stock.toast_article_desactive'))
    || pgv.redirect(pgv.call_ref('get_articles'));
END;
$function$;
COMMENT ON FUNCTION stock.post_article_delete(jsonb) IS 'Désactiver un article (soft delete) (i18n)';

CREATE OR REPLACE FUNCTION stock.post_article_save(p_data jsonb)
 RETURNS text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_id int;
BEGIN
  v_id := (p_data->>'id')::int;

  IF v_id IS NOT NULL AND v_id > 0 THEN
    UPDATE stock.article SET
      reference = p_data->>'reference',
      designation = p_data->>'designation',
      categorie = p_data->>'categorie',
      unite = p_data->>'unite',
      prix_achat = nullif(p_data->>'prix_achat', '')::numeric,
      seuil_mini = coalesce(nullif(p_data->>'seuil_mini', '')::numeric, 0),
      fournisseur_id = nullif(p_data->>'fournisseur_id', '')::int,
      catalog_article_id = nullif(p_data->>'catalog_article_id', '')::int,
      notes = coalesce(p_data->>'notes', '')
    WHERE id = v_id;

    RETURN pgv.toast(pgv.t('stock.toast_article_modifie'))
      || pgv.redirect(pgv.call_ref('get_article', jsonb_build_object('p_id', v_id)));
  ELSE
    INSERT INTO stock.article (reference, designation, categorie, unite, prix_achat, seuil_mini, fournisseur_id, catalog_article_id, notes)
    VALUES (
      p_data->>'reference',
      p_data->>'designation',
      p_data->>'categorie',
      p_data->>'unite',
      nullif(p_data->>'prix_achat', '')::numeric,
      coalesce(nullif(p_data->>'seuil_mini', '')::numeric, 0),
      nullif(p_data->>'fournisseur_id', '')::int,
      nullif(p_data->>'catalog_article_id', '')::int,
      coalesce(p_data->>'notes', '')
    ) RETURNING id INTO v_id;

    RETURN pgv.toast(pgv.t('stock.toast_article_cree'))
      || pgv.redirect(pgv.call_ref('get_article', jsonb_build_object('p_id', v_id)));
  END IF;
END;
$function$;
COMMENT ON FUNCTION stock.post_article_save(jsonb) IS 'Créer ou modifier un article avec lien catalog optionnel (i18n)';

CREATE OR REPLACE FUNCTION stock.post_depot_save(p_data jsonb)
 RETURNS text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_id int;
BEGIN
  v_id := (p_data->>'id')::int;

  IF v_id IS NOT NULL AND v_id > 0 THEN
    UPDATE stock.depot SET
      nom = p_data->>'nom',
      type = p_data->>'type',
      adresse = nullif(p_data->>'adresse', '')
    WHERE id = v_id;

    RETURN pgv.toast(pgv.t('stock.toast_depot_modifie'))
      || pgv.redirect(pgv.call_ref('get_depot', jsonb_build_object('p_id', v_id)));
  ELSE
    INSERT INTO stock.depot (nom, type, adresse)
    VALUES (p_data->>'nom', p_data->>'type', nullif(p_data->>'adresse', ''))
    RETURNING id INTO v_id;

    RETURN pgv.toast(pgv.t('stock.toast_depot_cree'))
      || pgv.redirect(pgv.call_ref('get_depot', jsonb_build_object('p_id', v_id)));
  END IF;
END;
$function$;
COMMENT ON FUNCTION stock.post_depot_save(jsonb) IS 'Créer ou modifier un dépôt (i18n)';

CREATE OR REPLACE FUNCTION stock.post_inventaire_valider(p_data jsonb)
 RETURNS text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_depot_id int := (p_data->>'p_depot_id')::int;
  v_key text;
  v_val text;
  v_article_id int;
  v_qty_reelle numeric;
  v_qty_theorique numeric;
  v_ecart numeric;
  v_nb_ajustements int := 0;
BEGIN
  IF NOT EXISTS (SELECT 1 FROM stock.depot WHERE id = v_depot_id AND actif) THEN
    RETURN pgv.toast(pgv.t('stock.err_depot_not_found'), 'error');
  END IF;

  FOR v_key, v_val IN SELECT key, value FROM jsonb_each_text(p_data) WHERE key LIKE 'qty_%'
  LOOP
    v_article_id := replace(v_key, 'qty_', '')::int;
    v_qty_reelle := v_val::numeric;
    v_qty_theorique := stock._stock_actuel(v_article_id, v_depot_id);
    v_ecart := v_qty_reelle - v_qty_theorique;

    IF v_ecart = 0 THEN
      CONTINUE;
    END IF;

    INSERT INTO stock.mouvement (article_id, depot_id, type, quantite, reference)
    VALUES (v_article_id, v_depot_id, 'inventaire', v_ecart,
            'INV-' || to_char(now(), 'YYYYMMDD'));

    v_nb_ajustements := v_nb_ajustements + 1;
  END LOOP;

  IF v_nb_ajustements = 0 THEN
    RETURN pgv.toast(pgv.t('stock.toast_stock_conforme'))
      || pgv.redirect(pgv.call_ref('get_inventaire', jsonb_build_object('p_depot_id', v_depot_id)));
  END IF;

  RETURN pgv.toast(format(pgv.t('stock.toast_inventaire_valide'), v_nb_ajustements))
    || pgv.redirect(pgv.call_ref('get_depot', jsonb_build_object('p_id', v_depot_id)));
END;
$function$;
COMMENT ON FUNCTION stock.post_inventaire_valider(jsonb) IS 'Valide un inventaire physique — génère mouvements d écart (i18n)';

CREATE OR REPLACE FUNCTION stock.post_mouvement_save(p_data jsonb)
 RETURNS text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_type text;
  v_article_id int;
  v_depot_id int;
  v_dest_id int;
  v_qty numeric;
  v_pu numeric;
  v_art stock.article;
BEGIN
  v_type := p_data->>'type';
  v_article_id := (p_data->>'article_id')::int;
  v_depot_id := (p_data->>'depot_id')::int;
  v_dest_id := nullif(p_data->>'depot_destination_id', '')::int;
  v_qty := (p_data->>'quantite')::numeric;
  v_pu := nullif(p_data->>'prix_unitaire', '')::numeric;

  SELECT * INTO v_art FROM stock.article WHERE id = v_article_id;
  IF NOT FOUND THEN
    RETURN pgv.toast(pgv.t('stock.err_article_not_found'), 'error');
  END IF;

  IF v_type = 'transfert' AND v_dest_id IS NULL THEN
    RETURN pgv.toast(pgv.t('stock.err_depot_dest_requis'), 'error');
  END IF;
  IF v_type = 'transfert' AND v_depot_id = v_dest_id THEN
    RETURN pgv.toast(pgv.t('stock.err_depot_src_dest_identiques'), 'error');
  END IF;

  IF v_type = 'sortie' THEN
    IF stock._stock_actuel(v_article_id, v_depot_id) < v_qty THEN
      RETURN pgv.toast(pgv.t('stock.err_stock_insuffisant'), 'error');
    END IF;
  END IF;

  IF v_type = 'entree' THEN
    INSERT INTO stock.mouvement (article_id, depot_id, type, quantite, prix_unitaire, reference, notes)
    VALUES (v_article_id, v_depot_id, 'entree', v_qty, coalesce(v_pu, v_art.prix_achat), nullif(p_data->>'reference', ''), coalesce(p_data->>'notes', ''));

    PERFORM stock._recalc_pmp(v_article_id);
    IF v_pu IS NOT NULL THEN
      UPDATE stock.article SET prix_achat = v_pu WHERE id = v_article_id;
    END IF;

  ELSIF v_type = 'sortie' THEN
    INSERT INTO stock.mouvement (article_id, depot_id, type, quantite, prix_unitaire, reference, notes)
    VALUES (v_article_id, v_depot_id, 'sortie', -v_qty, v_art.pmp, nullif(p_data->>'reference', ''), coalesce(p_data->>'notes', ''));

  ELSIF v_type = 'transfert' THEN
    IF stock._stock_actuel(v_article_id, v_depot_id) < v_qty THEN
      RETURN pgv.toast(pgv.t('stock.err_stock_insuffisant_transfert'), 'error');
    END IF;

    INSERT INTO stock.mouvement (article_id, depot_id, type, quantite, prix_unitaire, reference, depot_destination_id, notes)
    VALUES (v_article_id, v_depot_id, 'transfert', -v_qty, v_art.pmp, nullif(p_data->>'reference', ''), v_dest_id, coalesce(p_data->>'notes', ''));

    INSERT INTO stock.mouvement (article_id, depot_id, type, quantite, prix_unitaire, reference, depot_destination_id, notes)
    VALUES (v_article_id, v_dest_id, 'transfert', v_qty, v_art.pmp, nullif(p_data->>'reference', ''), v_depot_id, coalesce(p_data->>'notes', ''));

  ELSIF v_type = 'inventaire' THEN
    DECLARE
      v_stock_actuel numeric;
      v_ecart numeric;
    BEGIN
      v_stock_actuel := stock._stock_actuel(v_article_id, v_depot_id);
      v_ecart := v_qty - v_stock_actuel;

      IF v_ecart = 0 THEN
        RETURN pgv.toast(pgv.t('stock.toast_stock_correct'));
      END IF;

      INSERT INTO stock.mouvement (article_id, depot_id, type, quantite, prix_unitaire, reference, notes)
      VALUES (v_article_id, v_depot_id, 'inventaire', v_ecart, v_art.pmp,
              'INV-' || to_char(now(), 'YYYYMMDD'),
              format('Inventaire: %s -> %s (écart: %s)', v_stock_actuel, v_qty, v_ecart));
    END;
  END IF;

  RETURN pgv.toast(pgv.t('stock.toast_mvt_enregistre'))
    || pgv.redirect(pgv.call_ref('get_mouvements'));
END;
$function$;
COMMENT ON FUNCTION stock.post_mouvement_save(jsonb) IS 'Enregistrer un mouvement de stock avec recalcul PMP (i18n)';

